  'grants.how.step1.details': { pl: 'Skandias Talentsmie\nBank: DNB\nKonto: 1520 23 71008\nTytuł: „Składka członkowska – imię i nazwisko”', no: 'Skandias Talentsmie\nBank: DNB\nKonto: 1520 23 71008\nBetalingsmelding: «Medlemskontingent – fornavn og etternavn»', en: 'Skandias Talentsmie\nBank: DNB\nAccount: 1520 23 71008\nTitle: "Membership fee – first and last name"' },
