  'grants.footer.joinNow': { pl: 'Dołącz już dziś i zapewnij sobie oraz swojej rodzinie dostęp do wszystkiego, co najlepsze w Skandias Talentsmie!', no: 'Bli med i dag og sikre deg og din familie tilgang til det beste fra Skandias Talentsmie!', en: 'Join today and ensure you and your family access to the best of Skandias Talentsmie!' },
  'grants.footer.contactBtn': { pl: 'Kontakt z nami', no: 'Kontakt oss', en: 'Contact us' },

  // JoinUs Page
  'join.title': { pl: 'Dołącz do naszej kuźni!', no: 'Bli med i vår smie!', en: 'Join our forge!' },
  'join.subtitle': { pl: 'Masz duszę artysty? Tworzysz coś wyjątkowego własnymi rękami? Skandias Talentsmie to przestrzeń dla wszystkich, którzy chcą rozwijać swoje pasje i dzielić się nimi z innymi.', no: 'Har du en kunstnerisk sjel? Skaper du noe unikt med egne hender? Skandias Talentsmie er et rom for alle som ønsker å utvikle sine lidenskaper og dele dem med andre.', en: 'Do you have an artist\'s soul? Do you create something unique with your own hands? Skandias Talentsmie is a space for everyone who wants to develop their passions and share them with others.' },
  'join.why.title': { pl: 'Dlaczego warto?', no: 'Hvorfor er det verdt det?', en: 'Why join us?' },
  'join.why.1': { pl: 'Twoja pasja stanie się widoczna – pokaż światu swój talent.', no: 'Din lidenskap vil bli synlig – vis verden ditt talent.', en: 'Your passion will become visible – show the world your talent.' },
  'join.why.2': { pl: 'Pomożesz innym – unikatowe rzeczy są coraz bardziej poszukiwane.', no: 'Du vil hjelpe andre – unike ting er stadig mer ettertraktet.', en: 'You will help others – unique things are increasingly sought after.' },
  'join.why.3': { pl: 'Znajdziesz klientów i współpracowników.', no: 'Du vil finne kunder og samarbeidspartnere.', en: 'You will find customers and collaborators.' },
  'join.why.4': { pl: 'Docenią Twoją pracę – rękodzieło z duszą wygrywa z masówką.', no: 'De vil sette pris på ditt arbeid – håndverk med sjel vinner over masseproduksjon.', en: 'They will appreciate your work – handicrafts with soul win over mass production.' },
  'join.offer.title': { pl: 'Co oferujemy?', no: 'Hva tilbyr vi?', en: 'What do we offer?' },
  'join.offer.1': { pl: 'Promocję twórców i pomoc w docieraniu do odbiorców.', no: 'Promotering av skapere og hjelp til å nå ut til publikum.', en: 'Promotion of creators and help in reaching audiences.' },
  'join.offer.2': { pl: 'Organizację warsztatów i wydarzeń regionalnych.', no: 'Organisering av workshoper og regionale arrangementer.', en: 'Organization of workshops and regional events.' },
  'join.offer.3': { pl: 'Budowanie społeczności, w której każdy może się rozwijać.', no: 'Bygge et fellesskap der alle kan utvikle seg.', en: 'Building a community where everyone can develop.' },
  'join.offer.4': { pl: 'Wspieranie pasjonatów w budowaniu rozpoznawalności.', no: 'Støtte lidenskapelige i å bygge anerkjennelse.', en: 'Supporting enthusiasts in building recognition.' },
  'join.steps.title': { pl: 'Wystarczy tylko:', no: 'Alt som kreves er:', en: 'All it takes is:' },
  'join.steps.1': { pl: 'Wypełnić formularz zgłoszeniowy', no: 'Fyll ut søknadsskjemaet', en: 'Fill out the application form' },
  'join.steps.2': { pl: 'Dokonać wpłaty członkowskiej', no: 'Betal medlemskontingenten', en: 'Pay the membership fee' },
  'join.steps.3': { pl: 'I gotowe!', no: 'Og ferdig!', en: 'And you\'re done!' },
  'join.action.title': { pl: 'Gotowy by zaprezentować swój talent?', no: 'Klar for å presentere ditt talent?', en: 'Ready to present your talent?' },
  'join.action.desc': { pl: 'Skontaktuj się z nami bezpośrednio przez nasz oficjalny formularz.', no: 'Kontakt oss direkte via vårt offisielle skjema.', en: 'Contact us directly through our official form.' },
  'join.action.btn': { pl: 'Przejdź do kontaktu', no: 'Gå til kontakt', en: 'Go to contact' },

